import { NextRequest, NextResponse } from 'next/server'
import { createClient } from '@supabase/supabase-js'

export async function POST(req: NextRequest) {
  const supabase = createClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.SUPABASE_SECRET_KEY!
  )
  try {
    const cookie = req.cookies.get('claspire_session')
    if (!cookie) {
      return NextResponse.json({ error: 'Not authenticated' }, { status: 401 })
    }

    const session = JSON.parse(cookie.value)
    const userId = session.id

    const { post_id, content } = await req.json()

    if (!post_id || !content?.trim()) {
      return NextResponse.json({ error: 'Invalid input' }, { status: 400 })
    }

    // Insert answer
    const { data: answer, error: insertError } = await supabase
      .from('answers')
      .insert({
        post_id,
        author_id: userId,
        content: content.trim(),
        created_at: new Date().toISOString()
      })
      .select('*, users(full_name, branch, year)')
      .single()

    if (insertError) {
      console.error('Answer insert error:', insertError)
      return NextResponse.json({ error: insertError.message }, { status: 500 })
    }

    // Award 5 RP to answerer
    const { data: user } = await supabase
      .from('users')
      .select('rise_points, answer_count')
      .eq('id', userId)
      .single()

    await supabase
      .from('users')
      .update({ 
        rise_points: (user?.rise_points || 0) + 5,
        answer_count: (user?.answer_count || 0) + 1
      })
      .eq('id', userId)

    await supabase
      .from('rise_points_log')
      .insert({
        user_id: userId,
        points: 5,
        reason: 'Answered a question 🤝',
        created_at: new Date().toISOString()
      })

    // Update post: increment answer_count and set is_answered
    const { data: postData } = await supabase
      .from('posts')
      .select('answer_count')
      .eq('id', post_id)
      .single()

    await supabase
      .from('posts')
      .update({ 
        answer_count: (postData?.answer_count || 0) + 1,
        is_answered: true 
      })
      .eq('id', post_id)

    return NextResponse.json({
      success: true,
      answer
    })

  } catch (err: any) {
    console.error('Answer API error:', err)
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 })
  }
}

import { NextRequest, NextResponse } from 'next/server'
import { createClient } from '@supabase/supabase-js'
import bcrypt from 'bcryptjs'

const supabase = createClient(
  process.env.NEXT_PUBLIC_SUPABASE_URL!,
  process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!
)

export async function POST(req: NextRequest) {
  try {
    const { email, role, profileData, password } = await req.json()

    // Validate password
    if (!password || password.length < 6) {
      return NextResponse.json(
        { error: 'Password minimum 6 characters required' },
        { status: 400 }
      )
    }

    // Check OTP was verified
    const { data: otpData, error: otpError } = await supabase
      .from('otp_store')
      .select('*')
      .eq('email', email)
      .eq('verified', true)
      .single()

    if (otpError || !otpData) {
      return NextResponse.json(
        { error: 'Email verification failed' },
        { status: 400 }
      )
    }

    // Check user already exists
    const { data: existingUser } = await supabase
      .from('users')
      .select('id')
      .eq('email', email)
      .single()

    if (existingUser) {
      return NextResponse.json(
        { error: 'Account already exists with this email' },
        { status: 400 }
      )
    }

    // Generate unique ID
    const year = new Date().getFullYear()
    const randomNum = Math.floor(10000 + Math.random() * 90000)
    const uniqueId = role === 'student'
      ? `CLS-${year}-${randomNum}` 
      : `CLS-S-${year}-${randomNum}` 

    // Create user with random UUID
    const userId = crypto.randomUUID()

    // Hash password
    const passwordHash = await bcrypt.hash(password, 10)

    // Force valid verification_type
    const safeProfileData = {
      ...profileData,
      verification_type: 'manual',
      verification_status: profileData.verification_status 
        || 'verified',
      is_verified: true,
    }

    // Validate college_id is proper UUID
    const collegeId = profileData.college_id
    const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i

    const safeCollegeId = collegeId && 
      uuidRegex.test(collegeId) 
      ? collegeId 
      : null  // ← null if not valid UUID

    // Debug log to verify college_id
    console.log('Creating user with college_id:', collegeId, '-> safeCollegeId:', safeCollegeId)

    // Insert user
    const { data: user, error: userError } = await supabase
      .from('users')
      .insert({
        id: userId,
        email,
        role,
        unique_id: uniqueId,
        password_hash: passwordHash,  // ← ADD THIS
        college_id: safeCollegeId, // Use validated UUID
        rise_points: 50,
        rp_level: 1,
        ...safeProfileData,
        created_at: new Date().toISOString(),
        updated_at: new Date().toISOString(),
        avatar_url: `https://api.dicebear.com/7.x/initials/svg?seed=${profileData.full_name.split(' ').map((n: string) => n[0]).join('').toUpperCase().slice(0, 2)}`
      })
      .select()
      .single()

    if (userError) {
      console.error('User create error:', userError)
      return NextResponse.json(
        { error: userError.message },
        { status: 500 }
      )
    }

    // Log rise points
    await supabase.from('rise_points_log').insert({
      user_id: userId,
      points: 50,
      reason: 'Joined Claspire 🎉'
    })

    // Give join bonus +1 RP
    await supabase
      .from('rise_points_log')
      .insert({
        user_id: userId,
        points: 1,
        reason: 'Welcome to Claspire! 🎉',
        created_at: new Date().toISOString()
      })

    // Update rise_points to 51
    // (50 default + 1 join bonus)
    await supabase
      .from('users')
      .update({
        rise_points: 51,
        last_visit_date: new Date()
          .toISOString().split('T')[0]
      })
      .eq('id', userId)

    // Auto-join own college community
    if (safeCollegeId) {
      // Get community id
      const { data: comm } = await supabase
        .from('communities')
        .select('id, member_count, senior_count')
        .eq('college_id', safeCollegeId)
        .single()

      if (comm) {
        // Check if already a member
        const { data: existingMember } = await supabase
          .from('community_members')
          .select('id')
          .eq('community_id', comm.id)
          .eq('user_id', userId)
          .single()

        // Only insert if not already a member
        if (!existingMember) {
          // Insert member
          await supabase
            .from('community_members')
            .insert({
              community_id: comm.id,
              user_id: userId,
              membership_type: 'joined',
              is_verified: true,
              role: role === 'senior'
                ? 'senior' : 'member',
              joined_at: new Date().toISOString()
            })

          // Update count
          const newMemberCount =
            (comm.member_count || 0) + 1
          const newSeniorCount = role === 'senior'
            ? (comm.senior_count || 0) + 1
            : comm.senior_count || 0

          await supabase
            .from('communities')
            .update({
              member_count: newMemberCount,
              senior_count: newSeniorCount
            })
            .eq('id', comm.id)

          console.log(`Auto-joined user ${userId} to community ${comm.id}`)
        } else {
          console.log(`User ${userId} already a member of community ${comm.id}`)
        }
      }
    }

    // Store session in cookie
    const sessionData = {
      id: userId,
      email,
      role,
      unique_id: uniqueId,
      full_name: profileData.full_name,
      college_id: safeCollegeId,
      verification_status: profileData.verification_status,
      is_verified: true,        // ← ADD this!
      is_premium: false,        // ← ADD this!
    }

    // Debug log to show session data
    console.log('Session data being stored:', sessionData)

    // Clean up OTP
    await supabase
      .from('otp_store')
      .delete()
      .eq('email', email)

    const response = NextResponse.json({
      success: true,
      user: sessionData,
      uniqueId
    })

    // Set session cookie
    response.cookies.set('claspire_session', 
      JSON.stringify(sessionData), {
        httpOnly: true,
        secure: process.env.NODE_ENV === 'production',
        sameSite: 'lax',
        maxAge: 60 * 60 * 24 * 30 // 30 days
      }
    )

    console.log('Session cookie set:', sessionData.email, sessionData.role)

    // Add a small delay to ensure cookie is set
    await new Promise(resolve => setTimeout(resolve, 100))

    return response

  } catch (error) {
    console.error('Create user error:', error)
    return NextResponse.json(
      { error: 'Internal server error' },
      { status: 500 }
    )
  }
}

import { NextRequest, NextResponse } from 'next/server'
import { createClient } from '@supabase/supabase-js'
import bcrypt from 'bcryptjs'

const supabase = createClient(
  process.env.NEXT_PUBLIC_SUPABASE_URL!,
  process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!
)

export async function POST(req: NextRequest) {
  try {
    const { email, password, role } = await req.json()

    if (!email || !password) {
      return NextResponse.json(
        { error: 'Email and password required' },
        { status: 400 }
      )
    }

    // Get user
    const { data: user, error } = await supabase
      .from('users')
      .select('*')
      .eq('email', email)
      .single()

    if (error || !user) {
      return NextResponse.json(
        { error: 'Account not found. Please sign up.' },
        { status: 404 }
      )
    }

    // Role validation
    if (role && user.role !== role) {
      return NextResponse.json(
        { error: `This email is associated with a ${user.role === 'senior' ? 'Senior' : 'Student'} account.` },
        { status: 403 }
      )
    }

    // Check password
    if (!user.password_hash) {
      return NextResponse.json(
        { error: 'Password not set. Please sign up again.' },
        { status: 400 }
      )
    }

    const isValid = await bcrypt.compare(password, user.password_hash)

    if (!isValid) {
      return NextResponse.json(
        { error: 'Wrong password. Please try again.' },
        { status: 401 }
      )
    }

    // Create session
    const sessionData = {
      id: user.id,
      email: user.email,
      role: user.role,
      unique_id: user.unique_id,
      full_name: user.full_name,
      college_id: user.college_id || null,  // ← ADD this!
      is_verified: user.is_verified,        // ← ADD this!
      is_premium: user.is_premium || false, // ← ADD this!
    }

    // Debug log to show session data
    console.log('Login session data:', sessionData)

    const response = NextResponse.json({
      success: true,
      user: sessionData
    })

    response.cookies.set(
      'claspire_session',
      JSON.stringify(sessionData),
      {
        httpOnly: true,
        secure: process.env.NODE_ENV === 'production',
        sameSite: 'lax',
        maxAge: 60 * 60 * 24 * 30,
        path: '/'
      }
    )

    return response

  } catch (error: any) {
    console.error('Login error:', error)
    return NextResponse.json(
      { error: 'Login failed. Try again.' },
      { status: 500 }
    )
  }
}

import { NextRequest, NextResponse } from 'next/server'
import Mailjet from 'node-mailjet'
import { createClient } from '@supabase/supabase-js'

const supabase = createClient(
  process.env.NEXT_PUBLIC_SUPABASE_URL!,
  process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!
)

const mailjet = new Mailjet({
  apiKey: process.env.MAILJET_API_KEY!,
  apiSecret: process.env.MAILJET_SECRET_KEY!
})

export async function POST(req: NextRequest) {
  try {
    const { email } = await req.json()

    if (!email) {
      return NextResponse.json(
        { error: 'Email is required' },
        { status: 400 }
      )
    }

    // Generate 6 digit OTP
    const otp = Math.floor(
      100000 + Math.random() * 900000
    ).toString()

    const expiresAt = new Date(
      Date.now() + 10 * 60 * 1000
    ).toISOString()

    // Delete old OTPs
    await supabase
      .from('otp_store')
      .delete()
      .eq('email', email)

    // Store new OTP
    const { error: dbError } = await supabase
      .from('otp_store')
      .insert({
        email,
        otp,
        expires_at: expiresAt,
        verified: false
      })

    if (dbError) {
      console.error('DB Error:', dbError)
      return NextResponse.json(
        { error: 'Failed to store OTP' },
        { status: 500 }
      )
    }

    // Send via Mailjet
    const result = await mailjet
      .post('send', { version: 'v3.1' })
      .request({
        Messages: [
          {
            From: {
              Email: process.env.MAILJET_FROM_EMAIL,
              Name: 'Claspire'
            },
            To: [{ Email: email }],
            Subject: `${otp} - Your Claspire OTP`,
            HTMLPart: `
              <div style="font-family:Arial,sans-serif;
                max-width:480px;margin:0 auto;
                padding:32px;background:#ffffff;">

                <div style="text-align:center;
                  margin-bottom:32px;">
                  <h1 style="font-size:24px;
                    color:#0A0A0A;margin:0;">
                    🎓 Claspire
                  </h1>
                  <p style="color:#9CA3AF;
                    font-size:14px;margin-top:4px;">
                    Your college community
                  </p>
                </div>

                <h2 style="font-size:20px;
                  color:#0A0A0A;margin-bottom:8px;">
                  Verify your email
                </h2>
                <p style="color:#6B7280;font-size:14px;
                  line-height:1.6;margin-bottom:24px;">
                  Use this OTP to complete your signup.
                  Valid for 10 minutes only.
                </p>

                <div style="background:#F3F0FF;
                  border-radius:12px;padding:24px;
                  text-align:center;margin:24px 0;">
                  <p style="font-size:13px;color:#7C3AED;
                    font-weight:600;margin:0 0 8px;">
                    YOUR OTP
                  </p>
                  <p style="font-size:40px;font-weight:800;
                    color:#7C3AED;letter-spacing:8px;margin:0;">
                    ${otp}
                  </p>
                  <p style="font-size:12px;color:#9CA3AF;
                    margin:8px 0 0;">
                    Expires in 10 minutes
                  </p>
                </div>

                <p style="color:#9CA3AF;font-size:12px;
                  text-align:center;line-height:1.6;">
                  Do not share this OTP with anyone.<br/>
                  Claspire team will never 
                  ask for your OTP.
                </p>

                <hr style="border:none;
                  border-top:1px solid #F3F4F6;
                  margin:24px 0;"/>

                <p style="color:#D1D5DB;font-size:11px;
                  text-align:center;">
                  © 2024 Claspire · 
                  India's College Community
                </p>
              </div>
            `
          }
        ]
      })

    console.log('Mailjet sent:', result.body)

    return NextResponse.json({
      success: true,
      message: 'OTP sent!'
    })

  } catch (error: any) {
    console.error('Send OTP error:', error)
    return NextResponse.json(
      { error: 'Failed to send OTP. Try again.' },
      { status: 500 }
    )
  }
}

import { NextRequest, NextResponse } from 'next/server'
import { createClient } from '@supabase/supabase-js'

const supabase = createClient(
  process.env.NEXT_PUBLIC_SUPABASE_URL!,
  process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!
)

export async function POST(req: NextRequest) {
  try {
    const { email, otp } = await req.json()

    if (!email || !otp) {
      return NextResponse.json(
        { error: 'Email and OTP required' },
        { status: 400 }
      )
    }

    // Get OTP record
    const { data, error } = await supabase
      .from('otp_store')
      .select('*')
      .eq('email', email)
      .eq('otp', otp)
      .eq('verified', false)
      .single()

    if (error || !data) {
      return NextResponse.json(
        { error: 'Invalid OTP. Please enter correct OTP' },
        { status: 400 }
      )
    }

    // Check expiry
    if (new Date(data.expires_at) < new Date()) {
      await supabase
        .from('otp_store')
        .delete()
        .eq('email', email)

      return NextResponse.json(
        { error: 'OTP expired. Please resend OTP' },
        { status: 400 }
      )
    }

    // Mark verified
    await supabase
      .from('otp_store')
      .update({ verified: true })
      .eq('id', data.id)

    return NextResponse.json({
      success: true,
      message: 'OTP verified!'
    })

  } catch (error: any) {
    console.error('Verify OTP error:', error)
    return NextResponse.json(
      { error: 'Verification failed' },
      { status: 500 }
    )
  }
}

import { NextRequest, NextResponse } from 'next/server'
import { createClient } from '@supabase/supabase-js'

export async function POST(req: NextRequest) {
  const supabase = createClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.SUPABASE_SECRET_KEY!
  )

  try {
    const cookie = req.cookies.get('claspire_session')
    let userId = null

    if (cookie) {
      try {
        const session = JSON.parse(cookie.value)
        userId = session.id
      } catch (e) {
        console.warn('Failed to parse optional session for college request')
      }
    }

    const { 
      college_name, short_name, location, state, 
      college_type, email_domain, website_url, additional_info 
    } = await req.json()

    // Required fields check
    if (!college_name || !short_name || !location || !state || !college_type || !email_domain) {
      return NextResponse.json({ error: 'Missing required fields' }, { status: 400 })
    }

    // Check if duplicate in colleges table
    const { data: existingCollege } = await supabase
      .from('colleges')
      .select('id')
      .ilike('name', college_name)
      .single()

    if (existingCollege) {
      return NextResponse.json({ error: 'This college is already on Claspire!' }, { status: 400 })
    }

    // Check duplicate pending requests
    const { data: existingRequest } = await supabase
      .from('college_requests')
      .select('id')
      .ilike('college_name', college_name)
      .eq('status', 'pending')
      .maybeSingle()

    if (existingRequest) {
      return NextResponse.json({ error: "Already requested, we're reviewing it!" }, { status: 400 })
    }

    // Insert request
    const { error: insertError } = await supabase
      .from('college_requests')
      .insert({
        college_name,
        short_name,
        location,
        state,
        college_type,
        email_domain,
        website_url,
        additional_info,
        requested_by: userId,
        status: 'pending',
        created_at: new Date().toISOString()
      })

    if (insertError) {
      console.error('College request error:', insertError)
      return NextResponse.json({ error: insertError.message }, { status: 500 })
    }

    return NextResponse.json({
      success: true,
      message: "Coming Soon! Your request has been recorded."
    })

  } catch (err: any) {
    console.error('Server error:', err)
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 })
  }
}

export async function GET(req: NextRequest) {
    const supabase = createClient(
      process.env.NEXT_PUBLIC_SUPABASE_URL!,
      process.env.SUPABASE_SECRET_KEY!
    )

    try {
      const { data: requests, error } = await supabase
        .from('college_requests')
        .select(`
          id, college_name, short_name, status, created_at
        `)
        .order('created_at', { ascending: false })

      if (error) {
        return NextResponse.json({ error: error.message }, { status: 500 })
      }

      return NextResponse.json({ success: true, requests })
    } catch (err: any) {
      return NextResponse.json({ error: 'Internal server error' }, { status: 500 })
    }
}

