        is_pinned, created_at, tags,
        users!posts_author_id_fkey (
          full_name, unique_id,
          role, is_verified, avatar_url
        )
      `)
      .eq('community_id', community.id)
      .or(
        // Own college = see all posts
        // Other college = public only
        isOwnCollege
          ? 'visibility.eq.public,visibility.eq.private'
          : 'visibility.eq.public'
      )
      .order('created_at', { ascending: false })
      .limit(50)

    // 6. Fetch jobs only if permitted
    let jobs = null
    const canViewJobs = [
      'own_junior', 'own_senior', 'premium'
    ].includes(userRole)

    if (canViewJobs) {
      const { data } = await supabase
        .from('jobs')
        .select('*')
        .eq('community_id', community.id)
        .eq('is_active', true)
        .order('created_at', { ascending: false })
        .limit(10)
      jobs = data || []
    }

    // 7. Fetch webinars only if permitted
    let webinars = null
    const canViewWebinars = [
      'own_junior', 'own_senior', 'premium'
    ].includes(userRole)

    if (canViewWebinars) {
      const { data } = await supabase
        .from('webinars')
        .select(`
          *,
          users (
            full_name, designation, company
          )
        `)
        .eq('community_id', community.id)
        .in('status', ['upcoming', 'live'])
        .order('scheduled_at', { ascending: true })
        .limit(5)
      webinars = data || []
    }

    return NextResponse.json({
      success: true,
      community,
      verifiedJuniors: finalJuniorsCount,
      verifiedSeniors: finalSeniorsCount,
      posts: posts || [],
      jobs,
      webinars,
      userRole,
      isAlreadyMember,
      canPost: ['own_junior', 'own_senior']
        .includes(userRole),
      canAnswer: userRole === 'own_senior',
      canPostJob: userRole === 'own_senior',
      canHostWebinar: userRole === 'own_senior',
      canViewJobs,
      canViewWebinars,
    })

  } catch (err: any) {
    console.error('Community fetch error:', err)
    return NextResponse.json(
      { error: 'Server error' },
      { status: 500 }
    )
  }
}

import { NextRequest, NextResponse } from 'next/server'
import { createClient } from '@supabase/supabase-js'

const supabase = createClient(
  process.env.NEXT_PUBLIC_SUPABASE_URL!,
  process.env.SUPABASE_SECRET_KEY!
)

export async function POST(req: NextRequest) {
  try {
    const cookie = req.cookies.get('claspire_session')
    if (!cookie) {
      return NextResponse.json(
        { error: 'Not authenticated' },
        { status: 401 }
      )
    }

    const session = JSON.parse(cookie.value)
    const userId = session.id

    // Check if user is a senior
    const { data: user, error: userError } = await supabase
      .from('users')
      .select('role, rise_points, college_id')
      .eq('id', userId)
      .single()

    if (userError || user?.role !== 'senior') {
      return NextResponse.json(
        { error: 'Only seniors can post jobs' },
        { status: 403 }
      )
    }

    const body = await req.json()
    const {
      company_name,
      role,
      salary_range,
      location,
      job_type,
      description, // Used for job link/description
      requirements,
      deadline,
      referral_available,
      is_active = true
    } = body

    // Find the community ID for the user's college
    const { data: comm } = await supabase
      .from('communities')
      .select('id')
      .eq('college_id', user.college_id)
      .single()

    if (!comm) {
      return NextResponse.json(
        { error: 'Community not found for your college' },
        { status: 404 }
      )
    }

    // Insert job
    const { data: job, error: jobError } = await supabase
      .from('jobs')
      .insert({
        posted_by: userId,
        community_id: comm.id,
        company_name,
        role,
        salary_range,
        location,
        job_type,
        description,
        requirements,
        deadline,
        referral_available,
        is_active,
        created_at: new Date().toISOString(),
        updated_at: new Date().toISOString()
      })
      .select()
      .single()

    if (jobError) {
      console.error('Job create error:', jobError)
      return NextResponse.json(
        { error: jobError.message },
        { status: 500 }
      )
    }

    // Reward senior with Rise Points (e.g., +20 RP for posting a job)
    const rpAmount = 20
    await supabase
      .from('rise_points_log')
      .insert({
        user_id: userId,
        points: rpAmount,
        reason: `Posted a job: ${role} at ${company_name} 💼`,
        created_at: new Date().toISOString()
      })

    await supabase
      .from('users')
      .update({
        rise_points: (user.rise_points || 0) + rpAmount
      })
      .eq('id', userId)

    return NextResponse.json({
      success: true,
      job,
      rpEarned: rpAmount
    })

  } catch (err: any) {
    console.error('Create job error:', err)
    return NextResponse.json(
      { error: 'Internal server error' },
      { status: 500 }
    )
  }
}

import { NextRequest, NextResponse } from 'next/server'
import { createClient } from '@supabase/supabase-js'

const supabase = createClient(
  process.env.NEXT_PUBLIC_SUPABASE_URL!,
  process.env.SUPABASE_SECRET_KEY!
)

export async function POST(req: NextRequest) {
  try {
    const cookie = req.cookies.get('claspire_session')
    if (!cookie) {
      return NextResponse.json({ error: 'Not authenticated' }, { status: 401 })
    }

    const user = JSON.parse(cookie.value)
    const { jobId, seniorId } = await req.json()

    if (!jobId || !seniorId) {
      return NextResponse.json({ error: 'Missing required fields' }, { status: 400 })
    }

    // 1. Check if already requested
    const { data: existing } = await supabase
      .from('referral_requests')
      .select('id')
      .eq('job_id', jobId)
      .eq('requester_id', user.id)
      .single()

    if (existing) {
      return NextResponse.json({ error: 'You have already requested a referral for this job' }, { status: 400 })
    }

    // 2. Fetch job details for notification/email context
    const { data: job } = await supabase
      .from('jobs')
      .select('company_name, role')
      .eq('id', jobId)
      .single()

    // 3. Create request
    const { error: requestError } = await supabase
      .from('referral_requests')
      .insert({
        job_id: jobId,
        requester_id: user.id,
        senior_id: seniorId,
        status: 'pending'
      })

    if (requestError) throw requestError

    // 4. Create notification for the senior
    await supabase
      .from('notifications')
      .insert({
