import { NextRequest, NextResponse } from 'next/server'
import { createClient } from '@supabase/supabase-js'

const supabase = createClient(
  process.env.NEXT_PUBLIC_SUPABASE_URL!,
  process.env.SUPABASE_SECRET_KEY!
)

export async function POST(req: NextRequest) {
  try {
    const cookie = req.cookies.get('claspire_session')
    if (!cookie) {
      return NextResponse.json(
        { error: 'Not authenticated' },
        { status: 401 }
      )
    }

    const session = JSON.parse(cookie.value)
    const userId = session.id
    const currentUser = session

    const body = await req.json()
    const {
      community_id,
      title,
      content,
      type = 'doubt',
      visibility = 'public',
      tags = [],
      is_pinned = false,
      image_url = null
    } = body

    // Ensure content is a string
    const contentStr = String(body.content || '').trim()

    // Validate
    if (!title?.trim()) {
      return NextResponse.json(
        { error: 'Title required' },
        { status: 400 }
      )
    }
    if (!contentStr) {
      return NextResponse.json(
        { error: 'Content required' },
        { status: 400 }
      )
    }
    if (!community_id) {
      return NextResponse.json(
        { error: 'Community required' },
        { status: 400 }
      )
    }

    // Check user is member of community (same logic as community API)
    let isMember = false
    if (currentUser) {
      // Get user and community details for role checking
      const { data: userData } = await supabase
        .from('users')
        .select('college_id, is_verified, role, is_premium')
        .eq('id', userId)
        .single()

      const { data: communityData } = await supabase
        .from('communities')
        .select('college_id')
        .eq('id', community_id)
        .single()

      if (userData && communityData) {
        const isOwnCollege = userData.college_id === communityData.college_id
        const isVerified = userData.is_verified
        const isSenior = userData.role === 'senior'
        const isPremium = userData.is_premium

        // Same logic as community API
        if ((isOwnCollege && isVerified) || isPremium) {
          isMember = true
        } else {
          // Check explicit membership for other cases
          const { data: member } = await supabase
            .from('community_members')
            .select('id, membership_type')
            .eq('community_id', community_id)
            .eq('user_id', userId)
            .eq('membership_type', 'joined')
            .single()

          isMember = !!member
        }
      }
    }

    if (!isMember) {
      return NextResponse.json(
        { error: 'Not a member of this community' },
        { status: 403 }
      )
    }

    // Create post
    const { data: post, error } = await supabase
      .from('posts')
      .insert({
        community_id,
        author_id: userId,
        title: title.trim(),
        content: contentStr,
        type,
        visibility,
        tags,
        is_pinned,
        image_url: image_url || null,
        upvote_count: 0,
        downvote_count: 0,
        answer_count: 0,
        view_count: 0,
        is_answered: false,
        created_at: new Date().toISOString(),
        updated_at: new Date().toISOString()
      })
      .select()
      .single()

    if (error) {
      console.error('Post create error:', error)
      return NextResponse.json(
        { error: error.message },
        { status: 500 }
      )
    }

    // Give RP for posting
    const { data: user } = await supabase
      .from('users')
      .select('rise_points, doubt_count, answer_count, referral_count')
      .eq('id', userId)
      .single()

    const rpAmount =
  type === 'doubt' ? 3
  : type === 'discussion' ? 2
  : type === 'experience' ? 8
  : type === 'referral_hunt' ? 5
  : type === 'resource' ? 6
  : 2

    await supabase
      .from('rise_points_log')
      .insert({
        user_id: userId,
        points: rpAmount,
        reason: `Posted a ${type}: "${title.slice(0, 40)}"`,
        created_at: new Date().toISOString()
      })

    await supabase
      .from('users')
      .update({
        rise_points: (user?.rise_points || 0) + rpAmount,
        doubt_count: type === 'doubt' ? (user?.doubt_count || 0) + 1 : user?.doubt_count,
        answer_count: type === 'answer' ? (user?.answer_count || 0) + 1 : user?.answer_count,
        referral_count: type === 'referral_hunt' ? (user?.referral_count || 0) + 1 : user?.referral_count
      })
      .eq('id', userId)

    // Update community post count
    await supabase.rpc('increment', {
      table_name: 'communities',
      column_name: 'post_count',
      row_id: community_id
    })

    return NextResponse.json({
      success: true,
      post,
      rpEarned: rpAmount
    })

  } catch (err: any) {
    console.error('Create post error:', err)
    return NextResponse.json(
      { error: 'Internal server error' },
      { status: 500 }
    )
  }
}

import { NextRequest, NextResponse }
  from 'next/server'
import { createClient }
  from '@supabase/supabase-js'

const supabase = createClient(
  process.env.NEXT_PUBLIC_SUPABASE_URL!,
  process.env.SUPABASE_SECRET_KEY!
)

export async function DELETE(
  req: NextRequest
) {
  try {
    // Auth check
    const cookie =
      req.cookies.get('claspire_session')
    if (!cookie) {
      return NextResponse.json(
        { error: 'Not authenticated' },
        { status: 401 }
      )
    }

    const session = JSON.parse(cookie.value)
    const userId = session.id

    const { post_id } = await req.json()

    if (!post_id) {
      return NextResponse.json(
        { error: 'Post ID required' },
        { status: 400 }
      )
    }

    // Verify post belongs to user
    const { data: post } = await supabase
      .from('posts')
      .select('id, author_id, title')
      .eq('id', post_id)
      .single()

    if (!post) {
      return NextResponse.json(
        { error: 'Post not found' },
        { status: 404 }
      )
    }

    // Only author can delete
    if (post.author_id !== userId) {
      return NextResponse.json(
        { error: 'Not authorized' },
        { status: 403 }
      )
    }

    // Delete votes first (foreign key)
    await supabase
      .from('votes')
      .delete()
      .eq('post_id', post_id)

    // Delete answers/comments
    await supabase
      .from('answers')
      .delete()
      .eq('post_id', post_id)

    // Delete post
    const { error } = await supabase
      .from('posts')
      .delete()
      .eq('id', post_id)

    if (error) {
      return NextResponse.json(
        { error: error.message },
        { status: 500 }
      )
    }

    // Remove RP that was given for post
    // (optional — deduct 3 RP)
    const { data: user } = await supabase
      .from('users')
      .select('rise_points')
      .eq('id', userId)
      .single()

    await supabase
      .from('users')
      .update({
        rise_points: Math.max(
          0,
          (user?.rise_points || 0) - 3
        )
      })
      .eq('id', userId)

    return NextResponse.json({
      success: true,
      message: 'Post deleted successfully'
    })

  } catch (err: any) {
    console.error('Delete error:', err)
    return NextResponse.json(
      { error: 'Internal server error' },
      { status: 500 }
    )
  }
}

import { NextRequest, NextResponse } from 'next/server'
import { createClient } from '@supabase/supabase-js'

const supabase = createClient(
  process.env.NEXT_PUBLIC_SUPABASE_URL!,
  process.env.SUPABASE_SECRET_KEY!
)

export async function POST(req: NextRequest) {
  try {
    // Authentication
    const cookie = req.cookies.get('claspire_session')
    if (!cookie) {
      return NextResponse.json(
        { error: 'Not authenticated' },
        { status: 401 }
      )
    }

    const session = JSON.parse(cookie.value)
    const userId = session.id

    const { post_id, vote_type } = await req.json()

    // Validate input
    if (!post_id || !vote_type || !['upvote', 'downvote'].includes(vote_type)) {
      return NextResponse.json(
        { error: 'Invalid input' },
        { status: 400 }
      )
    }

    // Verify post exists
    const { data: post, error: postError } = await supabase
      .from('posts')
      .select('id')
      .eq('id', post_id)
      .single()

    if (postError || !post) {
      return NextResponse.json(
        { error: 'Post not found' },
        { status: 404 }
      )
    }

    // Check existing vote
    const { data: existing, error: existingError } = await supabase
      .from('votes')
      .select('id, vote_type')
      .eq('post_id', post_id)
      .eq('user_id', userId)
      .single()

    if (existingError && existingError.code !== 'PGRST116') {
      // Real error, not "not found"
      throw existingError
    }

    let action: 'added' | 'removed' | 'switched'

    if (existing) {
      if (existing.vote_type === vote_type) {
        // Same vote → remove (toggle off)
        action = 'removed'

        // Remove vote
        await supabase
          .from('votes')
          .delete()
          .eq('id', existing.id)

        // Update post counts atomically
        const { data: currentPost } = await supabase
          .from('posts')
          .select('upvote_count, downvote_count')
          .eq('id', post_id)
          .single()

        const newUpvotes = vote_type === 'upvote' 
          ? Math.max(0, (currentPost?.upvote_count || 0) - 1)
          : currentPost?.upvote_count || 0

        const newDownvotes = vote_type === 'downvote'
          ? Math.max(0, (currentPost?.downvote_count || 0) - 1)
          : currentPost?.downvote_count || 0

        await supabase
          .from('posts')
          .update({
            upvote_count: newUpvotes,
            downvote_count: newDownvotes
          })
          .eq('id', post_id)

        return NextResponse.json({
          success: true,
          action: 'removed',
          vote: null,
          upvotes: newUpvotes,
          downvotes: newDownvotes
        })
      } else {
        // Different vote → switch
        action = 'switched'

        // Update vote
        await supabase
          .from('votes')
          .update({ vote_type })
          .eq('id', existing.id)

        // Update post counts atomically
        const { data: currentPost } = await supabase
          .from('posts')
          .select('upvote_count, downvote_count')
          .eq('id', post_id)
          .single()

        let newUpvotes, newDownvotes

        if (vote_type === 'upvote') {
          newUpvotes = (currentPost?.upvote_count || 0) + 1
          newDownvotes = Math.max(0, (currentPost?.downvote_count || 0) - 1)
        } else {
          newUpvotes = Math.max(0, (currentPost?.upvote_count || 0) - 1)
          newDownvotes = (currentPost?.downvote_count || 0) + 1
        }

        await supabase
          .from('posts')
          .update({
            upvote_count: newUpvotes,
            downvote_count: newDownvotes
          })
          .eq('id', post_id)

        return NextResponse.json({
          success: true,
          action: 'switched',
          vote: { vote_type },
          upvotes: newUpvotes,
          downvotes: newDownvotes
        })
      }
    } else {
      // New vote
      action = 'added'

      // Insert new vote
      const { error: insertError } = await supabase
        .from('votes')
        .insert({
          post_id,
          user_id: userId,
          vote_type,
          created_at: new Date().toISOString()
        })

      if (insertError) {
        throw insertError
      }

      // Update post counts atomically
      const { data: currentPost } = await supabase
        .from('posts')
        .select('upvote_count, downvote_count')
        .eq('id', post_id)
        .single()

      const newUpvotes = vote_type === 'upvote'
        ? (currentPost?.upvote_count || 0) + 1
        : currentPost?.upvote_count || 0

      const newDownvotes = vote_type === 'downvote'
        ? (currentPost?.downvote_count || 0) + 1
        : currentPost?.downvote_count || 0

      await supabase
        .from('posts')
        .update({
          upvote_count: newUpvotes,
          downvote_count: newDownvotes
        })
        .eq('id', post_id)

      // Award RP to author
      if (vote_type === 'upvote' && action === 'added') {
        // Fetch author_id
        const { data: authorData } = await supabase
          .from('posts')
          .select('author_id, title')
          .eq('id', post_id)
          .single()

        if (authorData && authorData.author_id !== userId) {
          // Award 1 RP
          const { data: user } = await supabase
            .from('users')
            .select('rise_points')
            .eq('id', authorData.author_id)
            .single()

          await supabase
            .from('users')
            .update({ rise_points: (user?.rise_points || 0) + 1 })
            .eq('id', authorData.author_id)

          await supabase
            .from('rise_points_log')
            .insert({
              user_id: authorData.author_id,
              points: 1,
              reason: `Upvote received on: "${authorData.title.slice(0, 30)}..."`,
              created_at: new Date().toISOString()
            })
        }
      }

      return NextResponse.json({
        success: true,
        action,
        vote: { vote_type },
        upvotes: newUpvotes,
        downvotes: newDownvotes
      })
    }

  } catch (err: any) {
    console.error('Vote error:', err)

    // Handle specific error cases
    if (err.code === '23505') {
      // Unique constraint violation - vote already exists
      return NextResponse.json(
        { error: 'You have already voted on this post' },
        { status: 409 }
      )
    }

    if (err.code === '23503') {
      // Foreign key constraint violation
      return NextResponse.json(
        { error: 'Invalid post or user' },
        { status: 400 }
      )
    }

    return NextResponse.json(
      { error: 'Internal server error' },
      { status: 500 }
    )
  }
}

import { NextRequest, NextResponse } from 'next/server'
import { createClient } from '@supabase/supabase-js'

export async function PATCH(req: NextRequest) {
  const supabase = createClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.SUPABASE_SECRET_KEY!
  )

  try {
    const cookie = req.cookies.get('claspire_session')
    if (!cookie) {
      return NextResponse.json({ error: 'Not authenticated' }, { status: 401 })
    }

    const session = JSON.parse(cookie.value)
    const userId = session.id

    const body = await req.json()
    const { 
      bio, branch, year, cgpa, linkedin_url, passout_year,
      company, designation, graduation_year 
    } = body

    // Validation
    if (cgpa !== undefined && (cgpa < 0 || cgpa > 10)) {
      return NextResponse.json({ error: 'CGPA must be between 0 and 10' }, { status: 400 })
    }

    if (year !== undefined && (year < 1 || year > 4)) {
      return NextResponse.json({ error: 'Year must be between 1 and 4' }, { status: 400 })
    }

    if (linkedin_url && !linkedin_url.startsWith('https://linkedin.com')) {
      return NextResponse.json({ error: 'LinkedIn URL must start with https://linkedin.com' }, { status: 400 })
    }

    // Only allow specific fields
    const updateData: any = {}
    const allowedFields = [
      'bio', 'branch', 'year', 'cgpa', 'linkedin_url', 'passout_year',
      'company', 'designation', 'graduation_year'
    ]

    allowedFields.forEach(field => {
      if (body[field] !== undefined) {
        updateData[field] = body[field]
      }
    })

    updateData.updated_at = new Date().toISOString()

    const { data: updatedUser, error } = await supabase
      .from('users')
      .update(updateData)
      .eq('id', userId)
      .select(`
        id, full_name, email, role,
        unique_id, rise_points, rp_level,
        doubt_count, answer_count,
        referral_count, webinar_count,
        is_verified, verification_status,
        bio, branch, year, cgpa, linkedin_url, passout_year,
        company, designation, graduation_year,
        avatar_url,
        colleges ( id, name, short_name, slug )
      `)
      .single()

    if (error) {
      console.error('Profile update error:', error)
      return NextResponse.json({ error: error.message }, { status: 500 })
    }

    const response = NextResponse.json({
      success: true,
      user: updatedUser
    })

    // Update session cookie to keep parity
    response.cookies.set(
      'claspire_session',
      JSON.stringify(updatedUser),
      {
        httpOnly: true,
        sameSite: 'lax',
        maxAge: 60 * 60 * 24 * 30,
        path: '/'
      }
    )

    return response

  } catch (err: any) {
    console.error('Server error:', err)
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 })
  }
}

import { NextRequest, NextResponse } from 'next/server'
import { createClient } from '@supabase/supabase-js'

const supabase = createClient(
  process.env.NEXT_PUBLIC_SUPABASE_URL!,
  process.env.SUPABASE_SECRET_KEY!
)

export async function POST(req: NextRequest) {
  try {
    const cookie = req.cookies.get('claspire_session')
    if (!cookie) {
      return NextResponse.json({ error: 'Not authenticated' }, { status: 401 })
    }

    const { referralId } = await req.json()
    if (!referralId) {
      return NextResponse.json({ error: 'Referral ID is required' }, { status: 400 })
    }

    // 1. Fetch referral details
    const { data: referral, error: fetchError } = await supabase
      .from('referral_requests')
      .select(`
        id, requester_id, senior_id, job_id, status,
        job:job_id ( company_name, role ),
        senior:senior_id ( full_name )
      `)
      .eq('id', referralId)
      .single()

    if (fetchError || !referral) {
      return NextResponse.json({ error: 'Referral request not found' }, { status: 404 })
    }

    if (referral.status !== 'pending') {
      return NextResponse.json({ error: 'Referral is already processed' }, { status: 400 })
    }

    // 2. Update referral status
    const { error: updateError } = await supabase
      .from('referral_requests')
      .update({ status: 'approved', updated_at: new Date().toISOString() })
      .eq('id', referralId)

    if (updateError) throw updateError

    // 3. Increment senior's referral count
    const { data: senior } = await supabase
      .from('users')
      .select('referral_count')
      .eq('id', referral.senior_id)
      .single()

    await supabase
      .from('users')
      .update({ referral_count: (senior?.referral_count || 0) + 1 })
      .eq('id', referral.senior_id)

    const ref = referral as any
    await supabase
      .from('notifications')
      .insert({
        user_id: ref.requester_id,
        title: 'Referral Approved! 🎉',
        content: `Your request for ${ref.job?.role} at ${ref.job?.company_name} has been approved by ${ref.senior?.full_name}.`,
        type: 'referral_approved',
        link: '/dashboard'
      })

    return NextResponse.json({ success: true, message: 'Referral approved successfully' })

  } catch (err: any) {
    console.error('Approval error:', err)
    return NextResponse.json({ error: 'Failed to approve referral' }, { status: 500 })
  }
}

