                  <button 
                    onClick={confirmReferral}
                    disabled={referring}
                    className="flex-1 bg-purple-600 text-white py-3 rounded-xl font-bold text-sm hover:opacity-90 transition-opacity disabled:opacity-50 flex items-center justify-center gap-2"
