export default function LoginPage() {
  const router = useRouter()
  const [activeRole, setActiveRole] = useState<'student' | 'senior'>('student')
  const [email, setEmail] = useState('')
  const [password, setPassword] = useState('')
  const [showPassword, setShowPassword] = useState(false)
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState('')

  const handleLogin = async () => {
    if (!email || !password) {
      setError('Email and password required')
      return
    }

    setLoading(true)
    setError('')

    try {
      const res = await fetch('/api/auth/login', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email, password, role: activeRole })
      })

      const data = await res.json()

      if (!res.ok) {
        setError(data.error || 'Login failed')
        return
      }

      // Save to localStorage
      localStorage.setItem(
        'claspire_user',
        JSON.stringify(data.user)
      )

      // Full reload for cookie
      if (data.user.role === 'senior') {
        window.location.href = '/dashboard/senior'
      } else {
        window.location.href = '/dashboard/junior'
      }

    } catch {
      setError('Network error. Try again.')
    } finally {
      setLoading(false)
    }
  }

  return (
    <div style={{
      minHeight: '100vh',
      background: '#F9FAFB',
      fontFamily: 'Plus Jakarta Sans, sans-serif'
    }}>
      <Navbar />
      <div style={{
