      )}
    </nav>
  )
}

'use client'
import { useState } from 'react'
import {
  X, Globe, Lock, ChevronDown,
  Loader2, Tag, AlertCircle, ImagePlus
} from 'lucide-react'
import { useRef } from 'react'
import { usePoints } from '@/contexts/PointsContext'

interface PostModalProps {
  isOpen: boolean
  onClose: () => void
  onSuccess: () => void
  communitySlug: string
  communityId: string
  userRole: string
}

export default function PostModal({
  isOpen,
  onClose,
  onSuccess,
  communitySlug,
  communityId,
  userRole
}: PostModalProps) {
  const { showAward } = usePoints()
  const [title, setTitle] = useState('')
  const [content, setContent] = useState('')
  const [type, setType] = useState<'doubt' | 'discussion' | 'experience' | 'referral_hunt' | 'resource'>('doubt')
  const [visibility, setVisibility] = useState<'public' | 'private'>('public')
  const [tagInput, setTagInput] = useState('')
  const [tags, setTags] = useState<string[]>([])
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState('')

  // Image Upload States
  const [image, setImage] = useState<File | null>(null)
  const [imagePreview, setImagePreview] = useState<string | null>(null)
  const [imageUploading, setImageUploading] = useState(false)
  const [imageUrl, setImageUrl] = useState<string | null>(null)
  const imageRef = useRef<HTMLInputElement>(null)

  if (!isOpen) return null

  const addTag = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' || e.key === ',') {
      e.preventDefault()
      const t = tagInput.trim()
        .toLowerCase()
        .replace(/[^a-z0-9]/g, '')
      if (t && !tags.includes(t) 
        && tags.length < 5) {
        setTags([...tags, t])
        setTagInput('')
      }
    }
  }

  const removeTag = (tag: string) => {
    setTags(tags.filter(t => t !== tag))
  }

  const handleImageSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0]
    if (!file) return

    // Validate
    const allowed = ['image/jpeg', 'image/jpg', 'image/png', 'image/webp']
    if (!allowed.includes(file.type)) {
      setError('Only JPG, PNG, WebP allowed')
      return
    }
    if (file.size > 5 * 1024 * 1024) {
      setError('Image max size is 5MB')
      return
    }

    // Preview
    const reader = new FileReader()
    reader.onload = () => {
      setImagePreview(reader.result as string)
    }
    reader.readAsDataURL(file)
    setImage(file)

    // Upload
    setImageUploading(true)
    setError('')
    try {
      const formData = new FormData()
      formData.append('file', file)
      formData.append('type', 'post_image')

      const res = await fetch('/api/upload', {
        method: 'POST',
        body: formData
      })
      const data = await res.json()

      if (res.ok && data.url) {
        setImageUrl(data.url)
      } else {
        setError(data.error || 'Image upload failed')
        setImage(null)
        setImagePreview(null)
      }
    } catch (err) {
      setError('Image upload failed')
      setImage(null)
      setImagePreview(null)
    } finally {
      setImageUploading(false)
    }
  }

  const removeImage = () => {
    setImage(null)
    setImagePreview(null)
    setImageUrl(null)
    if (imageRef.current) {
      imageRef.current.value = ''
    }
  }

  const handleSubmit = async () => {
    if (!title.trim()) {
      setError('Title is required')
      return
    }
    if (!content.trim()) {
      setError('Content is required')
      return
    }
    if (content.trim().length < 20) {
      setError(
        'Content must be at least 20 characters'
      )
      return
    }

    setError('')
    setLoading(true)

    try {
      const res = await fetch(
        '/api/posts/create',
        {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json'
          },
          body: JSON.stringify({
            community_id: communityId,
            title: title.trim(),
            content: content.trim(),
            type,
            visibility,
            tags,
            is_pinned: false,
            image_url: imageUrl || null
          })
        }
      )

      const data = await res.json()

      if (!res.ok) {
        setError(
          data.error || 'Failed to post'
        )
        return
      }

      // Show RP Award
      if (data.rpEarned) {
        let reason = "New post created! 🚀";
        if (type === 'doubt') reason = "Doubt posted! ❓";
        if (type === 'experience') reason = "Experience shared! ⭐";
        if (type === 'referral_hunt') reason = "Referral hunt posted! 🎯";
        if (type === 'resource') reason = "Resource shared! 📚";

        showAward(data.rpEarned, reason);
      }

      // Reset form
      setTitle('')
      setContent('')
      setType('doubt')
      setVisibility('public')
      setTags([])
      setTagInput('')
      setImage(null)
      setImagePreview(null)
      setImageUrl(null)

      onSuccess()
      onClose()

    } catch (err) {
      setError('Something went wrong')
    } finally {
      setLoading(false)
    }
  }

  return (
    <>
      {/* Backdrop */}
      <div
        onClick={onClose}
        style={{
          position: 'fixed',
          inset: 0,
          background: 'rgba(0,0,0,0.6)',
          zIndex: 1000,
          backdropFilter: 'blur(4px)'
        }}
      />

      {/* Modal */}
      <div style={{
        position: 'fixed',
        top: '50%',
        left: '50%',
        transform: 'translate(-50%, -50%)',
        width: 'min(600px, 95vw)',
        maxHeight: '90vh',
        overflowY: 'auto',
        background: 'white',
        borderRadius: 20,
        zIndex: 1001,
        boxShadow:
          '0 25px 60px rgba(0,0,0,0.25)',
        fontFamily: 'Plus Jakarta Sans, sans-serif'
      }}>

        {/* Header */}
        <div style={{
          padding: '20px 24px 16px',
          borderBottom: '1px solid #F3F4F6',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          position: 'sticky',
          top: 0,
          background: 'white',
          zIndex: 1,
          borderRadius: '20px 20px 0 0'
        }}>
          <div>
            <h2 style={{
              fontSize: 16,
              fontWeight: 800,
              color: '#111827',
              margin: '0 0 2px',
              fontFamily: 'Instrument Serif'
            }}>
              Create Post
            </h2>
            <p style={{
              fontSize: 11,
              color: '#9CA3AF',
              margin: 0,
              fontWeight: 500
            }}>
              Posting to c/{communitySlug}
            </p>
          </div>
          <button
            onClick={onClose}
            style={{
              width: 32, height: 32,
              borderRadius: '50%',
              border: '1px solid #F3F4F6',
              background: '#F9FAFB',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              cursor: 'pointer',
              color: '#6B7280'
            }}
          >
            <X size={16} />
          </button>
        </div>

        {/* Body */}
        <div style={{ padding: '20px 24px' }}>

          {/* Post Type */}
<div style={{ marginBottom: 16 }}>
  <p style={{
    fontSize: 11,
    fontWeight: 700,
    color: '#9CA3AF',
    letterSpacing: '0.06em',
    textTransform: 'uppercase',
    margin: '0 0 10px'
  }}>
    Post Type
  </p>

  <div style={{
    display: 'grid',
    gridTemplateColumns: '1fr 1fr',
    gap: 8
  }}>
    {([
      {
        key: 'doubt',
        icon: '❓',
        label: 'Doubt',
        desc: 'Ask a specific question',
        color: '#2563EB',
        bg: '#EFF6FF',
        border: '#BFDBFE'
      },
      {
