  : type === 'discussion'
    ? 'Share your thoughts, opinions or experiences. Ask others what they think...'
  : type === 'experience'
    ? 'Share your complete experience — company, process, tips, what to prepare. This helps your juniors a lot!'
  : type === 'referral_hunt'
    ? 'Include: Company name, Role, Your CGPA, Branch, Batch year, and why you want to work there.'
  : 'Share the resource — include links, key points, or upload material. Mention what it covers and who it helps.'
}
            value={content}
            onChange={e =>
              setContent(e.target.value)}
            rows={5}
            style={{
              width: '100%',
              fontSize: 14,
              color: '#374151',
              border: '1.5px solid #F3F4F6',
              borderRadius: 12,
              padding: '14px',
              outline: 'none',
              fontFamily: 'Plus Jakarta Sans',
              resize: 'vertical',
              lineHeight: 1.7,
              background: '#FAFAFA',
              marginBottom: 16,
              boxSizing: 'border-box'
            }}
          />

          {/* Image Upload Section */}
          <div style={{ marginBottom: 16 }}>
            {!imagePreview && (
              <button
                type="button"
                onClick={() => imageRef.current?.click()}
                style={{
                  display: 'flex',
                  alignItems: 'center',
                  gap: 8,
                  fontSize: 12,
                  fontWeight: 600,
                  color: '#6B7280',
                  background: '#F9FAFB',
                  border: '1.5px dashed #E5E7EB',
                  borderRadius: 10,
                  padding: '10px 16px',
                  cursor: 'pointer',
                  fontFamily: 'Plus Jakarta Sans',
                  transition: 'all 0.15s',
                  width: '100%',
                  justifyContent: 'center'
                }}
                onMouseEnter={e => {
                  (e.currentTarget as HTMLElement).style.borderColor = '#A78BFA'
                  ;(e.currentTarget as HTMLElement).style.color = '#7C3AED'
                  ;(e.currentTarget as HTMLElement).style.background = '#F5F3FF'
                }}
                onMouseLeave={e => {
                  (e.currentTarget as HTMLElement).style.borderColor = '#E5E7EB'
                  ;(e.currentTarget as HTMLElement).style.color = '#6B7280'
                  ;(e.currentTarget as HTMLElement).style.background = '#F9FAFB'
                }}
              >
                <ImagePlus size={15} />
                Add Image (optional)
              </button>
            )}

            {imagePreview && (
              <div style={{
                position: 'relative',
                borderRadius: 12,
                overflow: 'hidden',
                border: '1.5px solid #EDE9FE'
              }}>
                <img
                  src={imagePreview}
                  alt="Preview"
                  style={{
                    width: '100%',
                    maxHeight: 240,
                    objectFit: 'cover',
                    display: 'block'
                  }}
                />

                {imageUploading && (
                  <div style={{
                    position: 'absolute',
                    inset: 0,
                    background: 'rgba(0,0,0,0.5)',
                    display: 'flex',
                    flexDirection: 'column',
                    alignItems: 'center',
                    justifyContent: 'center',
                    gap: 8
                  }}>
                    <Loader2 size={28} color="white" style={{ animation: 'spin 1s linear infinite' }} />
                    <span style={{ fontSize: 12, color: 'white', fontWeight: 600 }}>Uploading...</span>
                  </div>
                )}

                {!imageUploading && imageUrl && (
                  <div style={{
                    position: 'absolute',
                    bottom: 8,
                    left: 8,
                    background: '#ECFDF5',
                    border: '1px solid #A7F3D0',
                    borderRadius: 100,
                    padding: '3px 10px',
                    fontSize: 10,
                    fontWeight: 700,
                    color: '#059669',
                    display: 'flex',
                    alignItems: 'center',
                    gap: 4
                  }}>
                    ✓ Uploaded
                  </div>
                )}

                <button
                  onClick={removeImage}
                  style={{
                    position: 'absolute',
                    top: 8,
                    right: 8,
                    width: 28,
                    height: 28,
                    borderRadius: '50%',
                    background: 'rgba(0,0,0,0.6)',
                    border: 'none',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    cursor: 'pointer',
                    color: 'white'
                  }}
                >
                  <X size={14} />
                </button>
              </div>
            )}

            <input
              ref={imageRef}
              type="file"
              accept="image/jpeg,image/jpg,image/png,image/webp"
              onChange={handleImageSelect}
              style={{ display: 'none' }}
            />
          </div>

          {/* Tags */}
          <div style={{ marginBottom: 20 }}>
            <div style={{
              display: 'flex',
              alignItems: 'center',
              gap: 8,
              border: '1.5px solid #F3F4F6',
              borderRadius: 10,
              padding: '8px 12px',
