'use client'
import { useState, useEffect } from 'react'
import { useRouter } from 'next/navigation'

interface User {
  id: string
  email: string
  role: 'student' | 'senior' | 'admin'
  unique_id: string
  full_name: string
  college_id: string | null
  avatar_url?: string
}

export function useAuth() {
  const [user, setUser] = useState<User | null>(null)
  const [loading, setLoading] = useState(true)
  const router = useRouter()

  useEffect(() => {
    fetchUser()
  }, [])

  const fetchUser = async (retryCount = 0) => {
    try {
      console.log('useAuth - fetching user...', retryCount > 0 ? `(retry ${retryCount})` : '')
      const res = await fetch('/api/auth/me')
      console.log('useAuth - response status:', res.status)

      if (res.ok) {
        const data = await res.json()
        console.log('useAuth - response data:', data)
        setUser(data.user || null)
      } else if (res.status === 401) {
        // 401 = not logged in, that's ok
        console.log('useAuth - not logged in (401)')
        setUser(null)
      } else {
        // Other errors - retry once
        if (retryCount < 1) {
          console.log('useAuth - retrying fetch...')
          setTimeout(() => fetchUser(retryCount + 1), 500)
        } else {
          console.error('useAuth - unexpected status after retry:', res.status)
          setUser(null)
        }
      }
    } catch (error) {
      console.error('useAuth - fetch error:', error)
      if (retryCount < 1) {
        console.log('useAuth - retrying fetch after error...')
        setTimeout(() => fetchUser(retryCount + 1), 500)
      } else {
        setUser(null)
      }
    } finally {
      if (retryCount === 0) {
        setLoading(false)
      }
    }
  }

  const signOut = async () => {
    try {
      await fetch('/api/auth/signout', { method: 'POST' })
    } catch {}
    setUser(null)
    router.push('/')
  }

  return { user, loading, signOut, refetch: fetchUser }
}

import { supabase, supabaseAdmin } from './supabase'

// 1. Send OTP to email
export async function sendOTP(email: string) {
  const { data, error } = await supabase.auth.signInWithOtp({ 
    email,
    options: {
      shouldCreateUser: false, // Don't create user yet, wait for profile creation
    }
  })

  return { data, error }
}

// 2. Verify OTP
export async function verifyOTP(email: string, token: string) {
  const { data, error } = await supabase.auth.verifyOtp({ 
    email, 
    token, 
    type: 'email' 
  })

  return { data, error }
}

// 3. Sign out
export async function signOut() {
  const { error } = await supabase.auth.signOut()
  return { error }
}

// 4. Get current user
export async function getCurrentUser() {
  const { data: { user }, error } = await supabase.auth.getUser()
  return { user, error }
}

// 5. Create user profile
export async function createUserProfile(data: {
  full_name: string,
  email: string,
  role: 'student' | 'senior',
  college_id: string,
  branch?: string,
  year?: number,
  passout_year?: number,
  company?: string,
  designation?: string,
  graduation_year?: number,
}) {
  try {
    // Generate unique ID
    const currentYear = new Date().getFullYear()
    const randomDigits = Math.floor(10000 + Math.random() * 90000)
    const prefix = data.role === 'senior' ? 'CLS-S' : 'CLS'
    const unique_id = `${prefix}-${currentYear}-${randomDigits}`

    // Get avatar initials
    const initials = data.full_name
      .split(' ')
      .map(word => word[0])
      .join('')
      .toUpperCase()
      .slice(0, 2)

    // Insert user profile
    const { data: profile, error } = await supabase
      .from('users')
      .insert({
        id: (await getCurrentUser()).user?.id, // Get from auth session
        full_name: data.full_name,
        email: data.email,
        role: data.role,
        college_id: data.college_id,
        unique_id: unique_id,
        branch: data.branch,
        year: data.year,
        passout_year: data.passout_year,
        company: data.company,
        designation: data.designation,
        graduation_year: data.graduation_year,
        avatar_url: `https://api.dicebear.com/7.x/initials/svg?seed=${initials}`,
        verification_status: 'pending',
        rise_points: data.role === 'senior' ? 500 : 0, // Seniors start with some RP
        rp_level: data.role === 'senior' ? 2 : 1,
      })
      .select()
      .single()

    if (error) {
      console.error('Error creating user profile:', error)
      return { profile: null, error }
    }

    // Add to community members
    if (data.college_id && profile) {
      const { error: memberError } = await supabase
        .from('community_members')
        .insert({
          community_id: data.college_id,
          user_id: profile.id,
          membership_type: 'joined',
          is_verified: false,
          role: data.role === 'senior' ? 'senior' : 'member'
        })

      if (memberError) {
        console.error('Error adding to community:', memberError)
      }
    }

    return { profile, error: null }

  } catch (error) {
    console.error('Error in createUserProfile:', error)
    return { profile: null, error }
  }
}

// Helper: Get user profile with college info
export async function getUserProfile(userId: string) {
  const { data, error } = await supabase
    .from('users')
    .select(`
      *,
      colleges (
        id,
        name,
        short_name,
        slug
      )
    `)
    .eq('id', userId)
    .single()

  return { profile: data, error }
}

// Helper: Update user profile
export async function updateUserProfile(userId: string, updates: any) {
  const { data, error } = await supabase
    .from('users')
    .update(updates)
    .eq('id', userId)
    .select()
    .single()

  return { profile: data, error }
}

// Helper: Check if email exists
export async function checkEmailExists(email: string) {
  const { data, error } = await supabase
    .from('users')
    .select('email')
    .eq('email', email)
    .single()

  return { exists: !!data, error }
}

const { createClient } = require('@supabase/supabase-js');

const supabase = createClient(
  process.env.NEXT_PUBLIC_SUPABASE_URL,
  process.env.SUPABASE_SECRET_KEY
);

const MISSING_DATA = [
  {
    slug: "sfr",
    name: "The Standard Fireworks Rajaratnam College for Women",
    short_name: "SFR College",
    location: "Sivakasi, Tamil Nadu",
    type: "Arts",
    state: "Tamil Nadu",
    display_name: "SFR College Hub"
  }
];

async function seed() {
  for (const item of MISSING_DATA) {
    console.log(`Processing ${item.name}...`);

    // Check college
    let { data: college } = await supabase
      .from('colleges')
      .select('id')
      .eq('name', item.name)
      .single();

    if (!college) {
      console.log(`Inserting college ${item.name}...`);
      const { data: newCollege, error } = await supabase
        .from('colleges')
        .insert({
          name: item.name,
          short_name: item.short_name,
          location: item.location,
          type: item.type,
          state: item.state
        })
        .select()
        .single();

      if (error) {
        console.error('College insert error:', error);
        continue;
      }
      college = newCollege;
    }

    // Check community
    const { data: community } = await supabase
      .from('communities')
      .select('id')
      .eq('slug', item.slug)
      .single();

    if (!community && college) {
      console.log(`Inserting community ${item.slug}...`);
      const { error } = await supabase
        .from('communities')
        .insert({
          slug: item.slug,
          display_name: item.display_name,
          college_id: college.id,
          member_count: 750,
          senior_count: 25,
          doubt_count: 45
        });

      if (error) console.error('Community insert error:', error);
    } else {
      console.log(`Community ${item.slug} already exists.`);
    }
  }
  console.log('Done.');
}

seed();
